# Let's check the entities graph for any aspirin/PubChem related data
result = sparql_query("""
SELECT ?s ?p ?o WHERE {
  GRAPH <http://localhost:8080/graph/entities> {
    ?s ?p ?o .
  }
}
LIMIT 50
""")
print(result)

# Try to find any aspirin or molecular formula related data
result1 = sparql_query("""
SELECT ?s ?p ?o WHERE {
  GRAPH <http://localhost:8080/graph/observations> {
    ?s ?p ?o .
  }
}
LIMIT 20
""")
print("Observations graph sample:")
print(result1)

# Try entity lookup for PubChem CID 2244
result2 = sparql_query("""
SELECT ?p ?o WHERE {
  GRAPH ?g {
    <http://localhost:8080/entity/2244> ?p ?o .
  }
}
""")
print("\nEntity 2244:")
print(result2)

# Search for any molecular formula data
result3 = sparql_query("""
SELECT ?s ?p ?o WHERE {
  ?s ?p ?o .
  FILTER(CONTAINS(STR(?o), "aspirin") || CONTAINS(STR(?o), "2244") || CONTAINS(STR(?o), "C9H8O4") || CONTAINS(STR(?p), "formula"))
}
LIMIT 10
""")
print("\nAspirin/formula search:")
print(result3)

